mapper.select:
SELECT FROM activity_bookings ab WHERE ab.destinations_norm IS NOT NULL AND (
ab.destinations_norm LIKE CONCAT('%', #{destination}, '%')
) ORDER BY ab.updated_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT 
FROM activity_bookings ab
WHERE ab.search_lat IS NOT NULL
  AND ab.search_lng IS NOT NULL
  AND ab.search_lat BETWEEN #{p.minLat} AND #{p.maxLat}
  AND ab.search_lng BETWEEN #{p.minLng} AND #{p.maxLng}
  AND (
    6371 * acos(
        LEAST(1.0, GREATEST(-1.0,
            cos(radians(#{p.latitude})) * cos(radians(ab.search_lat)) *
            cos(radians(ab.search_lng) - radians(#{p.longitude})) +
            sin(radians(#{p.latitude})) * sin(radians(ab.search_lat))
        ))
    )
  ) <= #{p.radiusKm}

    AND ab.price_amount >= #{p.minPrice}


    AND ab.price_amount <= #{p.maxPrice}


    AND ab.rating >= #{p.minRating}

ORDER BY ab.updated_at DESC
LIMIT #{p.limit} OFFSET #{p.offset}
